(function() {
var hos_ch_1_Verses = [
  {num:1,words:[["O le afioga a Ieova na oo atu ia Hosea le atalii o Peri,", "The word of the LORD that came unto Hosea,"], ["i ona po o Usia,", "the son of Beeri, in the days of Uzziah,"], ["Iotama,", "Jotham,"], ["Aasa,", "Ahaz,"], ["ma Esekia,", "and Hezekiah,"], ["o tupu o Iuta;", "kings of Judah, and in the days of Jeroboam the son of Joash,"], ["o ona po foi o Ierepoamo le atalii o Ioasa le tupu o Isaraelu.", "king of Israel."]]},
  {num:2,words:[["O le amataga o le afioga a Ieova ia Hosea.", "The beginning of the word of the LORD by Hosea."], ["Ua fetalai mai Ieova ia Hosea,", "And the LORD said to Hosea,"], ["Alu ia oe,", "Go,"], ["ia e fai avā i le fafine talitane, ma ia fai māu le fanau a le faitaaga,", "take unto thee a wife of whoredoms and children of whoredoms:"], ["auā ua matuā faitaaga lava le nuu,", "for the land hath committed great whoredom,"], ["ua o ese ia Ieova.", "departing from the LORD."]]},
  {num:3,words:[["Ona alu lea o ia ua fai mana avā o Komeri le afafine o Tipelaima,", "So he went and took Gomer the daughter of Diblaim;"], ["ua to ai foi o ia,", "which conceived,"], ["ua fanau mai ai lona atalii.", "and bare him a son."]]},
  {num:4,words:[["Ua fetalai mai foi Ieova ia te ia,", "And the LORD said unto him,"], ["Ia e faaigoa ia te ia,", "Call his name Jezreel;"], ["o Isereelu; auā e toe itiiti,", "for yet a little while,"], ["ona ou taui atu ai lea o le toto o Isereelu i le aiga o Ieu,", "and I will avenge the blood of Jezreel upon the house of Jehu,"], ["ou te faaumatia foi le malo o le aiga o Isaraelu.", "and will cause to cease the kingdom of the house of Israel."]]},
  {num:5,words:[["O lea aso ou te gauia ai le aufana a Isaraelu i le vanu o Isereelu.", "And it shall come to pass at that day, that I will break the bow of Israel in the valley of Jezreel."]]},
  {num:6,words:[["Ua toe to foi o ia,", "And she conceived again,"], ["ua fanau ai le tama teine; ona fetalai mai lea o Ieova ia te ia,", "and bare a daughter. And God said unto him,"], ["Ia e faaigoa ia te ia,", "Call her name Lo-ruhamah:"], ["o Loruama; auā ou te le toe alofa atu i le aiga o Isaraelu,", "for I will no more have mercy upon the house of Israel;"], ["a e ou te matuā aveesea i latou.", "but I will utterly take them away."]]},
  {num:7,words:[["A o le aiga o Iuta,", "But I will have mercy upon the house of Judah,"], ["ou te alofa i ai,", "and will save them by the LORD their God,"], ["ou te faaola ia te i latou ona o Ieova lo latou Atua;", "and will not save them by bow,"], ["ou te le faaola ia te i latou i le aufana, po o le pelu,", "nor by sword,"], ["po o le taua,", "nor by battle,"], ["po o solofanua,", "by horses,"], ["po o 'au e tietie i solofanua.", "nor by horsemen."]]},
  {num:8,words:[["Ua ia faate'a Loruama ma le susu;", "Now when she had weaned Lo-ruhamah,"], ["ona to ai lea o ia,", "she conceived,"], ["ua fanau mai ai le tama tane.", "and bare a son."]]},
  {num:9,words:[["Ona faapea mai ai lea a le Atua ,", "Then said God,"], ["Ia e faaigoa ia te ia,", "Call his name Lo-ammi:"], ["o Loama; auā e le so'u nuu outou,", "for ye are not my people,"], ["e le so outou Atua foi a'u.", "and I will not be your God."]]},
  {num:10,words:[["A o le faitau aofai o le fanauga a Isaraelu e pei o le oneone o le sami ia,", "Yet the number of the children of Israel shall be as the sand of the sea,"], ["e le mafuatia,", "which cannot be measured nor numbered;"], ["e le mafaitaulia;", "and it shall come to pass,"], ["o i le mea foi na faapeaina atu ai ia te i latou,", "that in the place where it was said unto them,"], ["E le so'u nuu outou,", "Ye are not my people,"], ["e iu ina faapeaina atu ai ia te i latou,", "there it shall be said unto them,"], ["O atalii o le Atua soifua outou .", "Ye are the sons of the living God."]]},
  {num:11,words:[["Ona faapotopotoina faatasi ai lea o le fanauga a Iuta,", "Then shall the children of Judah and the children of Israel be gathered together,"], ["atoa ma le fanauga a Isaraelu,", "and appoint themselves one head,"], ["latou te tofia foi le ta'ita'i e toatasi mo i latou, latou te o ae foi ma le nuu;", "and they shall come up out of the land:"], ["auā e sili le aso o Isereelu.", "for great shall be the day of Jezreel."]]},
];
renderVerseSet(hos_ch_1_Verses, 'hos-ch1-verses');

var hos_ch_2_Verses = [
  {num:1,words:[["-2 Ia outou faapea atu i o outou uso, Ama e;", "Say ye unto your brethren,"], ["ia faapea atu foi i o outou tuafafine, Ruama e. Ia outou finau atu i lo outou tinā,", "Ammi;"], ["ina finafinau atu ia; auā e le o la'u avā ia, e le o lana tane foi a'u;", "and to your sisters,"], ["ina lafoai ia e ia ana faitaaga ai ia te ia, ma ana mulilua foi ai le va o ona susu;", "Ruhamah."]]},
  {num:2,words:[["Ona ou faatauina ai lea o ia ma'u i tupe e sefulu ma le lima,", "Plead with your mother, plead:"], ["ma le omera o karite,", "for she is not my wife, neither am I her husband:"], ["ma le leteka o karite.", "let her therefore put away her whoredoms out of her sight, and her adulteries from between her breasts;"]]},
  {num:3,words:[["ne'i ou talaeseina ona ofu,", "Lest I strip her naked,"], ["ma tuu atu ia te ia pei ona i ai i le aso na fanau mai ai o ia,", "and set her as in the day that she was born,"], ["e avea foi o ia pei o se vao,", "and make her as a wilderness,"], ["ma avea foi pei o se nuu naumati,", "and set her like a dry land,"], ["ma ou faaumatia o ia i le fia inu.", "and slay her with thirst."]]},
  {num:4,words:[["Ou te le alofa atu i lana fanau,", "And I will not have mercy upon her children;"], ["auā o le fanau a le faitaaga i latou.", "for they be the children of whoredoms."]]},
  {num:5,words:[["Auā ua faitaaga lo latou tinā,", "For their mother hath played the harlot:"], ["ua agavale lava le na fanaua i latou; auā na ia faapea mai,", "she that conceived them hath done shamefully:"], ["Ou te mulimuli atu i e o mananao ia te au,", "for she said,"], ["o e o au mai a'u mea e a'i, ma o'u vai,", "I will go after my lovers,"], ["ma a'u fulufulu mamoe,", "that give me my bread and my water,"], ["ma a'u lino, ma a'u suāuu,", "my wool and my flax,"], ["ma a'u mea e inu.", "mine oil and my drink."]]},
  {num:6,words:[["O le mea lea,", "Therefore,"], ["faauta,", "behold,"], ["ou te pupuni ai lou ala i laau tuitui,", "I will hedge up thy way with thorns,"], ["ou te siosioina foi o ia i le pa,", "and make a wall,"], ["ia le iloa e ia ona ala.", "that she shall not find her paths."]]},
  {num:7,words:[["E mulimuli atu lava o ia i e o mananao ia te ia,", "And she shall follow after her lovers,"], ["a e le maua atu i latou e ia; e sailiili o ia ia te i latou,", "but she shall not overtake them;"], ["a e le iloa;", "and she shall seek them,"], ["ona faapea mai ai lea o ia,", "but shall not find them:"], ["Ou te alu,", "then shall she say,"], ["ou te toe foi i la'u tane muamua, auā sa sili lo'u manuia anamua,", "I will go and return to my first husband;"], ["i lo'u manuia i nei ona po.", "for then was it better with me than now."]]},
  {num:8,words:[["Auā na le iloa e ia,", "For she did not know that I gave her corn,"], ["o a'u lava sa foaiina atu ia te ia o saito,", "and wine,"], ["ma uaina, ma suāuu;", "and oil,"], ["na a'u faateleina foi ana ario,", "and multiplied her silver and gold,"], ["ma ana auro na latou saunia mo Paala.", "which they prepared for Baal."]]},
  {num:9,words:[["O le mea lea ou te toe foi ai, ma ave ese la'u saito i ona lava aso,", "Therefore will I return,"], ["ma la'u uaina i ona lava po;", "and take away my corn in the time thereof,"], ["ou te aveesea foi a'u fulufulu mamoe,", "and my wine in the season thereof,"], ["ma a'u lino, sa tuuina atu e ufiufi a'i lona le lavalavā.", "and will recover my wool and my flax given to cover her nakedness."]]},
  {num:10,words:[["O lenei, ou te faaali lana amio ulavale i luma o e o mananao ia te ia,", "And now will I discover her lewdness in the sight of her lovers,"], ["e leai foi se tasi na te laveaiina o ia ai lo'u lima.", "and none shall deliver her out of mine hand."]]},
  {num:11,words:[["Ou te faaumatia foi lona fiafia uma lava,", "I will also cause all her mirth to cease,"], ["o ana tausamiga,", "her feast days,"], ["ma ona masina faatoa vaaia,", "her new moons,"], ["ma ona sapati,", "and her sabbaths,"], ["atoa ma ona nuu uma.", "and all her solemn feasts."]]},
  {num:12,words:[["Ou te faaumatia ona vine,", "And I will destroy her vines and her fig trees,"], ["ma ona mati,", "whereof she hath said,"], ["na ia faapea mai ai, O o'u taui lava ia na au mai ia te au e i latou ua mananao ia te au;", "These are my rewards that my lovers have given me:"], ["e avea foi i latou ia te au ma vao matua,", "and I will make them a forest,"], ["e 'aina i latou e manu feai.", "and the beasts of the field shall eat them."]]},
  {num:13,words:[["Ua fetalai mai Ieova,", "And I will visit upon her the days of Baalim,"], ["Ou te taui atu ia te ia ona o ona po o Paala,", "wherein she burned incense to them,"], ["na ia faamu ai mea manogi ia te i latou; na ia tifitifi foi ia te ia i ona mama,", "and she decked herself with her earrings and her jewels,"], ["ma ona teuga,", "and she went after her lovers,"], ["na ia mulimuli atu foi i e na mananao ia te ia,", "and forgat me,"], ["a ua faagalogalo lava ia te au.", "saith the LORD."]]},
  {num:14,words:[["A e peitai a'u faauta,", "Therefore,"], ["ou te faaoleole ia te ia,", "behold,"], ["ma ta'ita'i ia te ia i le vao,", "I will allure her, and bring her into the wilderness,"], ["ou te faamafanafana ia te ia.", "and speak comfortably unto her."]]},
  {num:15,words:[["Ou te tuuina atu foi ia te ia ana tovine i lea mea,", "And I will give her her vineyards from thence,"], ["ma le vanu o Akori e fai ma faitotoa e faamoemoe ai;", "and the valley of Achor for a door of hope:"], ["e pese foi o ia i ai,", "and she shall sing there,"], ["faapei ona fai i ona po ina o teine muli o ia,", "as in the days of her youth,"], ["pei o aso foi na sau ai o ia i le nuu o Aikupito.", "and as in the day when she came up out of the land of Egypt."]]},
  {num:16,words:[["O loo faapea mai Ieova,", "And it shall be at that day,"], ["O le aso lava lea e oo ai ona e faaaigoa ia te au,", "saith the LORD,"], ["O Ise; e te le toe faaigoa ia te au,", "that thou shalt call me Ishi;"], ["O Paale.", "and shalt call me no more Baali."]]},
  {num:17,words:[["Auā ou te aveesea i lona gutu o igoa o Paala,", "For I will take away the names of Baalim out of her mouth,"], ["e le toe ta'ua lava i latou i o latou igoa.", "and they shall no more be remembered by their name."]]},
  {num:18,words:[["O le aso foi lea matou te osi ai ma i latou le feagaiga ma manu feai,", "And in that day will I make a covenant for them with the beasts of the field,"], ["ma manu felelei,", "and with the fowls of heaven,"], ["ma mea fetolofi i le eleele; ou te gausia foi le aufana ma le pelu,", "and with the creeping things of the ground:"], ["ma le taua ai le nuu,", "and I will break the bow and the sword and the battle out of the earth,"], ["o a'u e taooto ai i latou ma le filemu.", "and will make them to lie down safely."]]},
  {num:19,words:[["Ta te osi sa ta feagaiga ma a'u e faavavau;", "And I will betroth thee unto me for ever;"], ["ta te osi sa ta feagaiga ma a'u i le amiotonu,", "yea,"], ["ma le faamasinoga,", "I will betroth thee unto me in righteousness, and in judgment,"], ["ma le agalelei,", "and in lovingkindness,"], ["ma le alofa.", "and in mercies."]]},
  {num:20,words:[["Ta te osi sa ta feagaiga ma a'u ma le faamaoni;", "I will even betroth thee unto me in faithfulness:"], ["e te iloa foi Ieova.", "and thou shalt know the LORD."]]},
  {num:21,words:[["O loo faapea mai Ieova,", "And it shall come to pass in that day,"], ["O lea aso,", "I will hear,"], ["ou te tali atu ai,", "saith the LORD,"], ["ou te tali atu i le lagi,", "I will hear the heavens,"], ["o ia foi na te tali atu i le lalolagi.", "and they shall hear the earth;"]]},
  {num:22,words:[["E tali atu foi le lalolagi i le saito,", "And the earth shall hear the corn,"], ["ma le uaina,", "and the wine,"], ["ma le suāuu;", "and the oil;"], ["o i latou foi latou te tali atu ia Isereelu.", "and they shall hear Jezreel."]]},
  {num:23,words:[["Ou te totōina o ia i le eleele e fai mo'u;", "And I will sow her unto me in the earth;"], ["ou te alofa foi i le sa le alofagia;", "and I will have mercy upon her that had not obtained mercy;"], ["ou te faapea atu foi i le ua le so'u nuu,", "and I will say to them which were not my people,"], ["O lo'u nuu oe;", "Thou art my people;"], ["ona latou faapea mai ai lea,", "and they shall say,"], ["O lo matou Atua.", "Thou art my God."]]},
];
renderVerseSet(hos_ch_2_Verses, 'hos-ch2-verses');

var hos_ch_3_Verses = [
  {num:1,words:[["Ua fetalai mai Ieova ia te au,", "Then said the LORD unto me,"], ["Ia e toe alu,", "Go yet,"], ["ia e loto atu i se fafine o le ua loto i ai lana uo,", "love a woman beloved of her friend, yet an adulteress,"], ["a o le fafine mulilua ia,", "according to the love of the LORD toward the children of Israel,"], ["e pei ona alofa o Ieova i le fanauga a Isaraelu o e faasagasaga i atua ese,", "who look to other gods,"], ["ma mananao i ipu uaina.", "and love flagons of wine."]]},
  {num:2,words:[["Ona ou faatauina ai lea o ia ma'u i tupe e sefulu ma le lima,", "So I bought her to me for fifteen pieces of silver,"], ["ma le omera o karite,", "and for an homer of barley,"], ["ma le leteka o karite.", "and an half homer of barley:"]]},
  {num:3,words:[["Na a'u fai atu foi ia te ia,", "And I said unto her,"], ["E te nofo faatali mai ia te au i aso e tele,", "Thou shalt abide for me many days;"], ["aua e te faitaaga,", "thou shalt not play the harlot,"], ["aua e te nofo i se tane;", "and thou shalt not be for another man:"], ["ou te nofo faatali foi ia te oe.", "so will I also be for thee."]]},
  {num:4,words:[["Auā e tele aso e nonofo ai le fanauga a Isaraelu,", "For the children of Israel shall abide many days without a king,"], ["e leai se tupu,", "and without a prince,"], ["e leai se alii,", "and without a sacrifice,"], ["e leai se taulaga,", "and without an image,"], ["e leai se fata faitaulaga,", "and without an ephod,"], ["e leai foi se efota po o se tupua.", "and without teraphim:"]]},
  {num:5,words:[["E mulimuli ane,", "Afterward shall the children of Israel return,"], ["e toe foi mai le fanauga a Isaraelu,", "and seek the LORD their God,"], ["latou te saili ia Ieova lo latou Atua, ma Tavita lo latou tupu;", "and David their king;"], ["latou te matatau foi ia Ieova ma lona agalelei i ona po e gata ai.", "and shall fear the LORD and his goodness in the latter days."]]},
];
renderVerseSet(hos_ch_3_Verses, 'hos-ch3-verses');

var hos_ch_4_Verses = [
  {num:1,words:[["Le fanauga a Isaraelu e,", "Hear the word of the LORD,"], ["ia outou faalogologo mai i le afioga a Ieova;", "ye children of Israel:"], ["auā o loo ia Ieova le finauga ma e o nonofo i le nuu;", "for the LORD hath a controversy with the inhabitants of the land,"], ["auā e leai se faamaoni,", "because there is no truth,"], ["e leai se alofa,", "nor mercy,"], ["e leai foi se na te iloa le Atua i le nuu.", "nor knowledge of God in the land."]]},
  {num:2,words:[["O loo o tauto,", "By swearing,"], ["ma tala pepelo,", "and lying,"], ["ma fasioti tagata,", "and killing,"], ["ma gaoi,", "and stealing,"], ["ma mulilua,", "and committing adultery,"], ["ua latou faasaua lava,", "they break out,"], ["ua fepaia'i toto.", "and blood toucheth blood."]]},
  {num:3,words:[["O le mea lea e faanoanoa ai le nuu,", "Therefore shall the land mourn,"], ["e tauāu ina vaivai o i latou uma o e nonofo ai;", "and every one that dwelleth therein shall languish,"], ["atoa ma manu vaefa,", "with the beasts of the field, and with the fowls of heaven;"], ["ma manu felelei,", "yea,"], ["e mavae atu foi lava o i'a o le sami.", "the fishes of the sea also shall be taken away."]]},
  {num:4,words:[["A e aua ne'i i ai se tagata e finau atu,", "Yet let no man strive,"], ["ma aoai atu i se tasi tagata;", "nor reprove another:"], ["auā o lou nuu ua pei o e fefinauai ma le ositaulaga.", "for thy people are as they that strive with the priest."]]},
  {num:5,words:[["O lea e te paū ai i le ao,", "Therefore shalt thou fall in the day,"], ["e pauu foi le perofeta faatasi ma oe i le po;", "and the prophet also shall fall with thee in the night,"], ["ou te fasioti foi lou tinā.", "and I will destroy thy mother."]]},
  {num:6,words:[["Ua faaumatia lo'u nuu ina ua leai se poto;", "My people are destroyed for lack of knowledge:"], ["o oe foi na e tetee atu i le poto,", "because thou hast rejected knowledge,"], ["o le mea lea ou te tetee atu ai ia te oe, e le fai oe ma ositaulaga ia te au;", "I will also reject thee,"], ["ua e faagalogalo le tulafono a lou Atua,", "that thou shalt be no priest to me:"], ["o a'u foi,", "seeing thou hast forgotten the law of thy God,"], ["ou te faagalogalo i lau fanau.", "I will also forget thy children."]]},
  {num:7,words:[["E pei ona faatoateleina o i latou,", "As they were increased,"], ["ua faapea ona agasala mai o i latou ia te au;", "so they sinned against me:"], ["ou te liliu i le mā lo latou mamalu.", "therefore will I change their glory into shame."]]},
  {num:8,words:[["Ua latou aai le agasala a lo'u nuu,", "They eat up the sin of my people,"], ["ma ua latou naunau i lo latou leaga.", "and they set their heart on their iniquity."]]},
  {num:9,words:[["E oo ina gatusa lava o le nuu ma le ositaulaga;", "And there shall be, like people,"], ["ou te taui atu foi ia te i latou a latou amio,", "like priest:"], ["ou te taui foi ia te i latou a latou mea ua fai.", "and I will punish them for their ways, and reward them their doings."]]},
  {num:10,words:[["Auā latou te aai,", "For they shall eat,"], ["a e le maoona;", "and not have enough:"], ["e faitaaga i latou,", "they shall commit whoredom,"], ["a e le faatoateleina;", "and shall not increase:"], ["auā ua le toe usiusitai i latou ia Ieova.", "because they have left off to take heed to the LORD."]]},
  {num:11,words:[["O le faitaaga, ma le uaina, ma le uaina fou e aveeseina ai le loto.", "Whoredom and wine and new wine take away the heart."]]},
  {num:12,words:[["O lo'u nuu ua latou fesili i lo latou laau;", "My people ask counsel at their stocks,"], ["ua faasino mai ai lo latou tootoo ia te i latou;", "and their staff declareth unto them:"], ["auā o le fia faitaaga ua faaseseina ai i latou ,", "for the spirit of whoredoms hath caused them to err,"], ["ma ua latou o ese nai lo latou Atua e faitaaga ai.", "and they have gone a whoring from under their God."]]},
  {num:13,words:[["Ua latou faitaulaga i tumutumu o mauga,", "They sacrifice upon the tops of the mountains,"], ["ma faamu mea manogi i mea maupuepue, ma lalo ifo o aluna,", "and burn incense upon the hills,"], ["ma lipeno,", "under oaks and poplars and elms,"], ["ma tapeneto,", "because the shadow thereof is good:"], ["auā ua lelei lo latou paolo; o le mea lea e faitaaga ai o outou afafine,", "therefore your daughters shall commit whoredom,"], ["e mulilulua foi a outou avā.", "and your spouses shall commit adultery."]]},
  {num:14,words:[["Ou te le faasalaina o outou afafine pe a latou faitaaga,", "I will not punish your daughters when they commit whoredom,"], ["ma a outou avā pe a latou mulilulua;", "nor your spouses when they commit adultery:"], ["auā o i latou lava ua latou o ese faatasi ma fafine faitaaga,", "for themselves are separated with whores,"], ["ua latou faitaulaga faatasi ma fafine talitane;", "and they sacrifice with harlots:"], ["o le nuu foi ua le mafaufau e pauu i latou.", "therefore the people that doth not understand shall fall."]]},
  {num:15,words:[["Isaraelu e,", "Though thou,"], ["e ui ina e faitaaga,", "Israel,"], ["a e aua ne'i agasala Iuta;", "play the harlot,"], ["aua tou te o mai i Kilikala,", "yet let not Judah offend; and come not ye unto Gilgal,"], ["aua tou te o ae i Petavene,", "neither go ye up to Beth-aven,"], ["aua foi tou te tauto,", "nor swear,"], ["O loo soifua Ieova.", "The LORD liveth."]]},
  {num:16,words:[["Auā e faapei ona vaogata o se povi fafine taanoa, ua faapea ona vaogata o Isaraelu;", "For Israel slideth back as a backsliding heifer:"], ["a e fagaina i latou i nei ona po e Ieova e faapei o se tamai mamoe i le mea lautele.", "now the LORD will feed them as a lamb in a large place."]]},
  {num:17,words:[["Ua pipii Efaraima i tupua;", "Ephraim is joined to idols:"], ["ina tuu ai pea ia ia te ia.", "let him alone."]]},
  {num:18,words:[["A uma lo latou inuga'ava,", "Their drink is sour:"], ["ua matuā faitaaga i latou;", "they have committed whoredom continually: her rulers with shame do love,"], ["ua loto atu o latou alii i mea e masiasi ai.", "Give ye."]]},
  {num:19,words:[["Ua saisaitia o ia e le matagi i ona apaau,", "The wind hath bound her up in her wings,"], ["e masiasi foi i latou ona o a latou taulaga.", "and they shall be ashamed because of their sacrifices."]]},
];
renderVerseSet(hos_ch_4_Verses, 'hos-ch4-verses');

var hos_ch_5_Verses = [
  {num:1,words:[["Le au ositaulaga e,", "Hear ye this,"], ["faalogologo mai ia i lenei mea. Le aiga o Isaraelu e,", "O priests; and hearken,"], ["ina faalogologo mai ia. Le aiga o le tupu e,", "ye house of Israel;"], ["ina liliu mai ia o outou fofoga,", "and give ye ear,"], ["auā ua faasalaina outou,", "O house of the king;"], ["ua avea outou ma matāsele i Mesepa,", "for judgment is toward you, because ye have been a snare on Mizpah,"], ["ma upega ua folasia i Tapora.", "and a net spread upon Tabor."]]},
  {num:2,words:[["Ua faateleina le fasi e i latou ua liliu ese, a o a'u,", "And the revolters are profound to make slaughter,"], ["ou te aoai atu ia te i latou uma.", "though I have been a rebuker of them all."]]},
  {num:3,words:[["O a'u ua ou iloa Efaraima,", "I know Ephraim,"], ["o Isaraelu foi ua le lilo lava ia ia te au;", "and Israel is not hid from me:"], ["auā,", "for now,"], ["Efaraima e,", "O Ephraim,"], ["ua e faitaaga nei,", "thou committest whoredom,"], ["ua leaga Isaraelu.", "and Israel is defiled."]]},
  {num:4,words:[["Latou te le sauniuni a latou galuega ina ia latou liliu mai i lo latou Atua;", "They will not frame their doings to turn unto their God:"], ["auā o i totonu ia te i latou le fia faitaaga,", "for the spirit of whoredoms is in the midst of them,"], ["latou te le iloa Ieova.", "and they have not known the LORD."]]},
  {num:5,words:[["Ua molimau le faamaualuga o Isaraelu i o latou luma,", "And the pride of Israel doth testify to his face:"], ["e pauu Isaraelu ma Efaraima i a latou agasala;", "therefore shall Israel and Ephraim fall in their iniquity;"], ["e paū foi Iuta faatasi ma i latou.", "Judah also shall fall with them."]]},
  {num:6,words:[["Latou te o atu ma a latou mamoe ma a latou povi e sailiili atu ai ia Ieova;", "They shall go with their flocks and with their herds to seek the LORD;"], ["a e latou te le maua;", "but they shall not find him;"], ["ua afio ese o ia ia te i latou.", "he hath withdrawn himself from them."]]},
  {num:7,words:[["Ua pepelo i latou ia Ieova;", "They have dealt treacherously against the LORD:"], ["auā ua fanau e i latou a latou tama ese; o le a 'aina nei i latou,", "for they have begotten strange children:"], ["atoa ma o latou tofi i le masina e tasi .", "now shall a month devour them with their portions."]]},
  {num:8,words:[["Ia outou ilia le sofao i Kipea,", "Blow ye the cornet in Gibeah,"], ["ma le pu i Rama;", "and the trumpet in Ramah:"], ["ia outou alalaga i Petavene;", "cry aloud at Beth-aven,"], ["Peniamina e,", "after thee,"], ["o loo mulimuli atu o ia ia te oe.", "O Benjamin."]]},
  {num:9,words:[["E faatafunaina Efaraima i ona po o le aoaiga; ua ou faailoaina atu i itu aiga o Isaraelu,", "Ephraim shall be desolate in the day of rebuke:"], ["o le upu moni lava.", "among the tribes of Israel have I made known that which shall surely be."]]},
  {num:10,words:[["O alii o Iuta sa faapei o tagata e sii le tuaoi i latou;", "The princes of Judah were like them that remove the bound:"], ["ou te liligi atu lo'u ita faapei o le vai ia te i latou.", "therefore I will pour out my wrath upon them like water."]]},
  {num:11,words:[["Ua faasauaina Efaraima, ua lomia i le faamasinoga;", "Ephraim is oppressed and broken in judgment,"], ["auā ua usiusitai o ia ma lona loto i le poloaiga.", "because he willingly walked after the commandment."]]},
  {num:12,words:[["O a'u foi e pei o se mogamoga i Efaraima;", "Therefore will I be unto Ephraim as a moth,"], ["e pei o se mea e pala foi i le aiga o Iuta.", "and to the house of Judah as rottenness."]]},
  {num:13,words:[["Na iloa e Efaraima lona ma'i,", "When Ephraim saw his sickness,"], ["na iloa foi e Iuta lona manua,", "and Judah saw his wound,"], ["ona alu lea o Efaraima i Asuria,", "then went Ephraim to the Assyrian,"], ["na alu lana feau ia Iarepa le tupu;", "and sent to king Jareb:"], ["a ua le mafai lava ia te ia ona faamalolo ia te outou,", "yet could he not heal you,"], ["pe faamafuina o outou manua.", "nor cure you of your wound."]]},
  {num:14,words:[["Auā e avea a'u e pei o se leona ia Efaraima,", "For I will be unto Ephraim as a lion,"], ["e pei o se leona taanoa foi i le aiga o Iuta;", "and as a young lion to the house of Judah: I,"], ["o a'u lava ou te saeia ma alu ese,", "even I,"], ["ou te aveesea,", "will tear and go away; I will take away,"], ["e leai foi se na te laveaiina.", "and none shall rescue him."]]},
  {num:15,words:[["Ou te alu,", "I will go and return to my place,"], ["ou te toe foi lava i le mea ou te nofo ai,", "till they acknowledge their offence,"], ["seia faasalaina lava i latou, ma latou saili ia te au;", "and seek my face:"], ["latou te vave saili ia te au pe a puapuagatia i latou.", "in their affliction they will seek me early."]]},
];
renderVerseSet(hos_ch_5_Verses, 'hos-ch5-verses');

var hos_ch_6_Verses = [
  {num:1,words:[["O mai ia,", "Come,"], ["ina tatou toe foi atu ia Ieova;", "and let us return unto the LORD:"], ["auā o ia ua na saeia,", "for he hath torn,"], ["na te faamaloloina foi i tatou;", "and he will heal us;"], ["ua ia fasia,", "he hath smitten,"], ["na te fofoina foi i tatou.", "and he will bind us up."]]},
  {num:2,words:[["Na te faaolaina mai i tatou pe a mavae aso e lua;", "After two days will he revive us:"], ["a oo i lona tolu o aso na te faatutūina i tatou,", "in the third day he will raise us up,"], ["tatou te ola mai ai i ona luma.", "and we shall live in his sight."]]},
  {num:3,words:[["Tatou te iloa foi o loo o tatou tausisi atu ia iloa Ieova;", "Then shall we know,"], ["ua saunia lona afio atu e pei o le taeao,", "if we follow on to know the LORD:"], ["e afio mai foi o ia ia te i tatou e pei o le ua,", "his going forth is prepared as the morning; and he shall come unto us as the rain,"], ["e pei o le timu mulimuli ma le timu muamua i le eleele.", "as the latter and former rain unto the earth."]]},
  {num:4,words:[["Efaraima e,", "O Ephraim,"], ["se a ea se mea ou te faia ia te oe? Iuta e,", "what shall I do unto thee? O Judah,"], ["se a ea se mea ou te faia ia te oe? auā ua pei o le puao i le taeao la outou amio lelei,", "what shall I do unto thee? for your goodness is as a morning cloud,"], ["e pei o le sau foi i le vave ao ona mavae atu.", "and as the early dew it goeth away."]]},
  {num:5,words:[["O le mea lea ua ou fasia ai i latou e le au perofeta,", "Therefore have I hewed them by the prophets;"], ["ua ou fasiotia i latou i upu a lo'u gutu;", "I have slain them by the words of my mouth:"], ["o au faamasinoga foi o le malamalama e alu atu lea.", "and thy judgments are as the light that goeth forth."]]},
  {num:6,words:[["Auā o le alofa ou te loto i ai,", "For I desired mercy,"], ["a e le o le taulaga;", "and not sacrifice;"], ["ia iloa foi le Atua e sili lea i lo'u manatu i taulaga mu.", "and the knowledge of God more than burnt offerings."]]},
  {num:7,words:[["A ua latou soli le feagaiga, e pei o Atamu;", "But they like men have transgressed the covenant:"], ["ua latou pepelo ia te au i lea mea.", "there have they dealt treacherously against me."]]},
  {num:8,words:[["O Kiliata o le aai lea o e fai amio leaga, o loo leaga,", "Gilead is a city of them that work iniquity,"], ["i le toto.", "and is polluted with blood."]]},
  {num:9,words:[["Faapei ona lamalama i se tagata o e fao mea,", "And as troops of robbers wait for a man,"], ["e faapea foi le au ositaulaga ona fasioti tagata i le ala i Sekema;", "so the company of priests murder in the way by consent:"], ["auā ua ulavale i latou.", "for they commit lewdness."]]},
  {num:10,words:[["Ua a'u iloa i le aiga o Isaraelu le mea e matuā leaga;", "I have seen an horrible thing in the house of Israel:"], ["ua i ai le faitaaga o Efaraima,", "there is the whoredom of Ephraim,"], ["ua leaga Isaraelu.", "Israel is defiled."]]},
  {num:11,words:[["Iuta e,", "Also, O Judah,"], ["ua tuu mo oe lava le seleselegāsaito ina ua ou faafoisia le tafeaga a lo'u nuu.", "he hath set an harvest for thee, when I returned the captivity of my people."]]},
];
renderVerseSet(hos_ch_6_Verses, 'hos-ch6-verses');

var hos_ch_7_Verses = [
  {num:1,words:[["Na fai a a'u faamaloloina o Isaraelu,", "When I would have healed Israel,"], ["ona mānu mai ai lea o le leaga o Efaraima ma amio leaga a Samaria;", "then the iniquity of Ephraim was discovered,"], ["auā ua latou fai le amio pepelo;", "and the wickedness of Samaria: for they commit falsehood;"], ["e ulufale mai le gaoi,", "and the thief cometh in,"], ["a e osofia i fafo e le au fao mea.", "and the troop of robbers spoileth without."]]},
  {num:2,words:[["Latou to le faapea ifo i o latou loto, Ou te manatua la latou amio leaga uma;", "And they consider not in their hearts that I remember all their wickedness:"], ["o lenei,", "now their own doings have beset them about;"], ["ua siosiomia i latou i a latou lava galuega, ua i o'u luma ia mea.", "they are before my face."]]},
  {num:3,words:[["Latou te faafiafia le tupu i a latou amio leaga;", "They make the king glad with their wickedness,"], ["atoa ma alii i a latou tala pepelo.", "and the princes with their lies."]]},
  {num:4,words:[["Ua mulilulua i latou uma;", "They are all adulterers,"], ["pei se ogaumu i latou ua faaaasaina e le fai areto;", "as an oven heated by the baker, who ceaseth from raising after he hath kneaded the dough,"], ["ua le toe tafu pe a uma ona lolomi o le palugāfalaoa seia faafefeteina.", "until it be leavened."]]},
  {num:5,words:[["O le aso o lo tatou tupu na mama'i ai alii i le oona o uaina;", "In the day of our king the princes have made him sick with bottles of wine;"], ["na ia faaloaloa atu lona lima faatasi ma ē tauemu.", "he stretched out his hand with scorners."]]},
  {num:6,words:[["Auā ua latou faalatalata ma o latou loto,", "For they have made ready their heart like an oven,"], ["e pei o se ogaumu,", "whiles they lie in wait:"], ["a o latou o lamalama; ua aoina o moe lo latou fai areto,", "their baker sleepeth all the night;"], ["ua mu i le taeao pei se afi mumū.", "in the morning it burneth as a flaming fire."]]},
  {num:7,words:[["Ua aasa i latou uma e pei o se ogaumu,", "They are all hot as an oven,"], ["ua latou faaumatia o latou alii faamasino;", "and have devoured their judges;"], ["ua pauu o latou tupu uma,", "all their kings are fallen:"], ["e leai so latou e valaau ia te au.", "there is none among them that calleth unto me."]]},
  {num:8,words:[["O Efaraima ua numia o ia e ia faatasi ma le nuu;", "Ephraim, he hath mixed himself among the people;"], ["o Efaraima o le potoi areto ia e lei liua.", "Ephraim is a cake not turned."]]},
  {num:9,words:[["Ua faaumatia e tagata ese lona malosi,", "Strangers have devoured his strength,"], ["a ua le iloa e ia;", "and he knoweth it not:"], ["ua pule le sinā o lona lauulu,", "yea, gray hairs are here and there upon him,"], ["a ua le iloa e ia.", "yet he knoweth not."]]},
  {num:10,words:[["Ua molimau le faamaualuga o Isaraelu i o latou luma;", "And the pride of Israel testifieth to his face:"], ["e ui lava i ia mea uma, ua latou le toe foi ia Ieova lo latou Atua,", "and they do not return to the LORD their God,"], ["ua latou le saili foi ia te ia.", "nor seek him for all this."]]},
  {num:11,words:[["O Efaraima foi e pei o se lupe valea ia,", "Ephraim also is like a silly dove without heart:"], ["e leai sona mafaufau; latou te valaau ia Aikupito,", "they call to Egypt,"], ["ua o foi i latou i Asuria.", "they go to Assyria."]]},
  {num:12,words:[["A latou o,", "When they shall go,"], ["ou te lafo la'u upega i luga ia te i latou;", "I will spread my net upon them;"], ["ou te lafo i lalo ia te i latou pei ni manu felelei;", "I will bring them down as the fowls of the heaven; I will chastise them,"], ["ou te sasa foi ia te i latou e pei ona faalogo i ai lo latou potopotoga.", "as their congregation hath heard."]]},
  {num:13,words:[["O i talofa ia te i latou! auā ua sosola ese i latou ia te au;", "Woe unto them! for they have fled from me:"], ["ia malaia i latou! auā ua latou fouvale ia te au;", "destruction unto them! because they have transgressed against me:"], ["na ou togiola foi ia te i latou,", "though I have redeemed them,"], ["a ua latou tala pepelo ia leaga ai a'u.", "yet they have spoken lies against me."]]},
  {num:14,words:[["Ua le valaau mai i latou ia te au ma o latou loto,", "And they have not cried unto me with their heart,"], ["ina ua latou uio i o latou moega;", "when they howled upon their beds:"], ["latou te faapotopoto i saito ma uaina;", "they assemble themselves for corn and wine,"], ["latou te o ese ia te au.", "and they rebel against me."]]},
  {num:15,words:[["O a'u foi, na ou a'oa'o atu,", "Though I have bound and strengthened their arms,"], ["na ou faamalosiina o latou lima, a ua latou taupulepule i mea e leaga ai a'u.", "yet do they imagine mischief against me."]]},
  {num:16,words:[["Ua latou toe foi,", "They return,"], ["a e le o lē Silisili ese ua latou foi i ai;", "but not to the most High:"], ["e pei o le aufana pepelo i latou;", "they are like a deceitful bow:"], ["e pauu o latou alii i le pelu ona o le faasiasia o latou laulaufaiva;", "their princes shall fall by the sword for the rage of their tongue:"], ["e fai mo latou gao lea mea i le nuu o Aikupito.", "this shall be their derision in the land of Egypt."]]},
];
renderVerseSet(hos_ch_7_Verses, 'hos-ch7-verses');

var hos_ch_8_Verses = [
  {num:1,words:[["Ia e ili le pu;", "Set the trumpet to thy mouth. He shall come as an eagle against the house of the LORD,"], ["e sau o ia e pei o se aeto i le aiga o Ieova; auā ua latou soli la'u feagaiga,", "because they have transgressed my covenant,"], ["ma ua latou fouvale i la'u tulafono.", "and trespassed against my law."]]},
  {num:2,words:[["E alalaga i latou ia te au,", "Israel shall cry unto me,"], ["Lo matou Atua e, o Isaraelu i matou ,", "My God,"], ["ua matou iloa oe.", "we know thee."]]},
  {num:3,words:[["Ua lafoaiina e Isaraelu le mea lelei;", "Israel hath cast off the thing that is good:"], ["e tuliloaina o ia e le ua ita ia te ia .", "the enemy shall pursue him."]]},
  {num:4,words:[["Ua latou tofia tupu a e le mai ia te au;", "They have set up kings,"], ["ua latou tofia alii a e le iloa e a'u;", "but not by me:"], ["o latou ario,", "they have made princes, and I knew it not:"], ["ma o latou auro ua latou fai a'i tupua mo i latou,", "of their silver and their gold have they made them idols,"], ["ina ia faaumatia ai i latou .", "that they may be cut off."]]},
  {num:5,words:[["Samaria e,", "Thy calf,"], ["ua lafoaiina oe e lau tamai povi;", "O Samaria,"], ["ua tupu lo'u ita ia te i latou;", "hath cast thee off; mine anger is kindled against them:"], ["pe latou te le mafai seia afea ona mamā?", "how long will it be ere they attain to innocency?"]]},
  {num:6,words:[["Auā mai ia Isaraelu lava ia;", "For from Israel was it also:"], ["na faia o ia e le tufuga;", "the workman made it;"], ["e le o le Atua lava ia,", "therefore it is not God:"], ["o le mea lea e nutililiiina ai le tamai povi o Samaria.", "but the calf of Samaria shall be broken in pieces."]]},
  {num:7,words:[["Na latou luluina le matagi,", "For they have sown the wind,"], ["o le mea lea latou te selesele mai ai le afā;", "and they shall reap the whirlwind:"], ["ua leai sona tino;", "it hath no stalk:"], ["e le tupu se saito i le fuga,", "the bud shall yield no meal:"], ["a e afai e fua,", "if so be it yield,"], ["e 'aina e tagata ese.", "the strangers shall swallow it up."]]},
  {num:8,words:[["Ua faaumatia Isaraelu; latou te i ai nei i nuu ese,", "Israel is swallowed up:"], ["e pei o se ipu e leai sē fiafia i ai.", "now shall they be among the Gentiles as a vessel wherein is no pleasure."]]},
  {num:9,words:[["Auā ua latou o ae i Asuria,", "For they are gone up to Assyria,"], ["ua se asini o le vao ua nofo toatasi;", "a wild ass alone by himself:"], ["ua faaoloaina e Efaraima e o mananao ia te ia .", "Ephraim hath hired lovers."]]},
  {num:10,words:[["A e ui ina latou faaoloaina nuu ese,", "Yea,"], ["ou te faapotopoto nei ia te i latou;", "though they have hired among the nations, now will I gather them,"], ["e le pine ona tiga o i latou ona o le avega mai le tupu o alii.", "and they shall sorrow a little for the burden of the king of princes."]]},
  {num:11,words:[["Ua faia e Efaraima fata faitaulaga e tele, e agasala ai;", "Because Ephraim hath made many altars to sin,"], ["o le mea lea ua avea ai fata faitaulaga ma mea e agasala ai o ia.", "altars shall be unto him to sin."]]},
  {num:12,words:[["Ua ou tusi atu ia te ia o mea tetele i la'u tulafono;", "I have written to him the great things of my law,"], ["a ua ta'ua ia mea o mea ese.", "but they were counted as a strange thing."]]},
  {num:13,words:[["Latou te fai taulaga i manu e fai ma taulaga mo a'u,", "They sacrifice flesh for the sacrifices of mine offerings,"], ["ma latou aai ai;", "and eat it;"], ["a ua le talia i latou e Ieova;", "but the LORD accepteth them not;"], ["e manatua nei e ia a latou amio leaga,", "now will he remember their iniquity,"], ["ma taui i a latou agasala;", "and visit their sins:"], ["latou te toe foi i Aikupito.", "they shall return to Egypt."]]},
  {num:14,words:[["Auā ua faagalogalo e Isaraelu i Lē na faia o ia,", "For Israel hath forgotten his Maker,"], ["ua faatuina e ia o malumalu;", "and buildeth temples;"], ["o Iuta foi ua ia faateleina o aai nofo 'olo;", "and Judah hath multiplied fenced cities:"], ["ou te tuuina atu le afi i ana aai,", "but I will send a fire upon his cities,"], ["e faaumatia ai ona maota.", "and it shall devour the palaces thereof."]]},
];
renderVerseSet(hos_ch_8_Verses, 'hos-ch8-verses');

var hos_ch_9_Verses = [
  {num:1,words:[["Isaraelu e,", "Rejoice not,"], ["aua e te fiafia ma le olioli,", "O Israel,"], ["faapei o isi nuu;", "for joy, as other people:"], ["auā ua e alu ese i lou Atua e faitaaga ai;", "for thou hast gone a whoring from thy God,"], ["ua e fia fai taui i mea uma e sasa ai saito.", "thou hast loved a reward upon every cornfloor."]]},
  {num:2,words:[["E le fagaina i latou i le mea e sasa ai saito ma le soligāvine,", "The floor and the winepress shall not feed them,"], ["e oge ai uaina fou.", "and the new wine shall fail in her."]]},
  {num:3,words:[["Latou te le nonofo i le nuu o Ieova,", "They shall not dwell in the LORD'S land;"], ["a e toe foi Efaraima i Aikupito,", "but Ephraim shall return to Egypt,"], ["latou te aai mea leaga i Asuria.", "and they shall eat unclean things in Assyria."]]},
  {num:4,words:[["Latou te le fai taulaga ia Ieova i uaina,", "They shall not offer wine offerings to the LORD,"], ["e le fiafia o ia ia te i latou; o a latou taulaga,", "neither shall they be pleasing unto him:"], ["e ia te i latou ia,", "their sacrifices shall be unto them as the bread of mourners;"], ["peiseai o mea e 'ai a e faanoanoa, o i latou uma e aai ai e leaga ai i latou;", "all that eat thereof shall be polluted:"], ["auā o la latou mea e 'ai mā latou e le oo atu lea i le fale o Ieova.", "for their bread for their soul shall not come into the house of the LORD."]]},
  {num:5,words:[["Se a se mea tou te faia i le aso e fai ai le tausamiga,", "What will ye do in the solemn day,"], ["ma le aso e fai ai le taulaga ia Ieova?", "and in the day of the feast of the LORD?"]]},
  {num:6,words:[["Auā,", "For,"], ["faauta mai,", "lo,"], ["ua o i latou ne'i malaia;", "they are gone because of destruction:"], ["e faapotopotoina i latou e Aikupito,", "Egypt shall gather them up, Memphis shall bury them:"], ["e tanumia i latou e Mafi;", "the pleasant places for their silver,"], ["o mea matagofie o i ai o latou ario e vaoa ia i laau ogoogo;", "nettles shall possess them:"], ["e i ai i o latou fale o laau talatala.", "thorns shall be in their tabernacles."]]},
  {num:7,words:[["Ua oo mai ona po e taui ai,", "The days of visitation are come,"], ["ua oo mai ona po e totogi ai;", "the days of recompence are come;"], ["e iloa e Isaraelu;", "Israel shall know it:"], ["ua valea le perofeta,", "the prophet is a fool,"], ["ua valea lava le vaafaatau,", "the spiritual man is mad,"], ["ona o le tele o lau amio leaga,", "for the multitude of thine iniquity,"], ["ma le 'ino'ino tele.", "and the great hatred."]]},
  {num:8,words:[["O loo faatalitali Efaraima faatasi i lo'u Atua;", "The watchman of Ephraim was with my God:"], ["ua se mailei o e fāi manu le perofeta i ana amio uma;", "but the prophet is a snare of a fowler in all his ways,"], ["o le 'ino'ino i le fale o lona Atua.", "and hatred in the house of his God."]]},
  {num:9,words:[["Ua matuā amio leaga i latou,", "They have deeply corrupted themselves,"], ["faapei ona fai i ona po o Kipea;", "as in the days of Gibeah:"], ["e manatua e ia a latou agasala,", "therefore he will remember their iniquity,"], ["e taui atu i a latou amio leaga.", "he will visit their sins."]]},
  {num:10,words:[["Na ou maua Isaraelu,", "I found Israel like grapes in the wilderness;"], ["e pei o fuifui vine i le vao;", "I saw your fathers as the firstripe in the fig tree at her first time:"], ["na ou iloa o outou mātua e pei o uluai mati i le mati ina ua faatoa fua mai; a ua o i latou ia Paalapeoro,", "but they went to Baal-peor,"], ["ua vavae atu i latou i le mea e masiasi ai;", "and separated themselves unto that shame;"], ["ua inosia i latou e tusa ma le mea ua latou naunau i ai.", "and their abominations were according as they loved."]]},
  {num:11,words:[["O Efaraima e lele ese lo latou mamalu faapei o le manu lele,", "As for Ephraim,"], ["ai le fanauga,", "their glory shall fly away like a bird,"], ["ma le manava,", "from the birth, and from the womb,"], ["ma le faatoa afuafua.", "and from the conception."]]},
  {num:12,words:[["E ui ina latou tausi a latou fanau,", "Though they bring up their children,"], ["ou te aveeseina i latou i tagata;", "yet will I bereave them,"], ["oi talofa lava ia te i latou,", "that there shall not be a man left: yea,"], ["pe a a'u alu ese ia te i latou.", "woe also to them when I depart from them!"]]},
  {num:13,words:[["Ua totōina Efaraima i le mea matagofie,", "Ephraim,"], ["faapei ona ou iloa o Turo;", "as I saw Tyrus, is planted in a pleasant place:"], ["a o Efaraima na te ta'ita'iina atu lana fanau i le fasioti tagata.", "but Ephraim shall bring forth his children to the murderer."]]},
  {num:14,words:[["Ieova e,", "Give them,"], ["ia e avatu ia te i latou; se a foi se mea e te avatua? Ia e avatu ia te i latou le manava fanau le au,", "O LORD:"], ["ma susu e le susua.", "what wilt thou give? give them a miscarrying womb and dry breasts."]]},
  {num:15,words:[["O loo i Kilikala lo latou leaga uma;", "All their wickedness is in Gilgal:"], ["auā na ou 'ino'ino ia te i latou i lea mea,", "for there I hated them:"], ["ou te tulia i latou ai lo'u fale ina ua leaga mea ua latou faia; ou te le toe alofa ia te i latou;", "for the wickedness of their doings I will drive them out of mine house,"], ["o latou alii uma,", "I will love them no more:"], ["o e fouvale i latou.", "all their princes are revolters."]]},
  {num:16,words:[["Ua taia Efaraima,", "Ephraim is smitten,"], ["ua mago lo latou pogai;", "their root is dried up,"], ["latou te le fua mai ni fua;", "they shall bear no fruit: yea,"], ["afai foi latou te fananau,", "though they bring forth,"], ["ou te fasiotia la latou fanau pele.", "yet will I slay even the beloved fruit of their womb."]]},
  {num:17,words:[["E lafoaiina i latou e lo'u Atua,", "My God will cast them away,"], ["auā ua latou le faalogo ia te ia;", "because they did not hearken unto him:"], ["e taase i latou i nuu ese.", "and they shall be wanderers among the nations."]]},
];
renderVerseSet(hos_ch_9_Verses, 'hos-ch9-verses');

var hos_ch_10_Verses = [
  {num:1,words:[["O Isaraelu, o le vine ia e māfalā;", "Israel is an empty vine,"], ["ua ia fua mai ni fua e fai mona; faapei ona tele o lona fua,", "he bringeth forth fruit unto himself:"], ["ua faapea ona faateleina e ia o fata faitaulaga;", "according to the multitude of his fruit he hath increased the altars;"], ["faapei ona lelei o lona laueleele, ua faapea ona latou gaosi lelei o tupua.", "according to the goodness of his land they have made goodly images."]]},
  {num:2,words:[["Ua faalotoloto lua i latou;", "Their heart is divided;"], ["ua nofo sala nei i latou;", "now shall they be found faulty:"], ["na te lepetia a latou fata faitaulaga,", "he shall break down their altars,"], ["na te faaumatia a latou tupua.", "he shall spoil their images."]]},
  {num:3,words:[["Auā e faapea mai nei i latou,", "For now they shall say,"], ["Ua leai se tupu ia te i matou,", "We have no king,"], ["auā ua matou le matatau ia Ieova;", "because we feared not the LORD;"], ["se a foi se mea e faia e le tupu ia i matou?", "what then should a king do to us?"]]},
  {num:4,words:[["Ua latou fai mai upu, ua tauto pepelo,", "They have spoken words,"], ["ua osi le feagaiga;", "swearing falsely in making a covenant:"], ["e tupu ae foi le faamasinoga, e pei o laau oona i utu o fanua.", "thus judgment springeth up as hemlock in the furrows of the field."]]},
  {num:5,words:[["E fefefe e ua nonofo i Samaria ona o tamai povi o Petavene;", "The inhabitants of Samaria shall fear because of the calves of Beth-aven:"], ["auā e fetagisi ai ona tagata,", "for the people thereof shall mourn over it,"], ["o ona ositaulaga foi e na fiafia i ai;", "and the priests thereof that rejoiced on it, for the glory thereof,"], ["auā o lona mamalu ua te'a ma ia.", "because it is departed from it."]]},
  {num:6,words:[["E avea foi lenei mea i Asuria e fai ma mea alofa i le tupu o Iarepa;", "It shall be also carried unto Assyria for a present to king Jareb:"], ["e mā Efaraima,", "Ephraim shall receive shame,"], ["e masiasi foi Isaraelu ona o lana lava pule.", "and Israel shall be ashamed of his own counsel."]]},
  {num:7,words:[["O Samaria ua fano lona tupu,", "As for Samaria,"], ["e pei o si fasi laau i le fogāvai.", "her king is cut off as the foam upon the water."]]},
  {num:8,words:[["E faaumatia foi mea maualuga i Avene,", "The high places also of Aven,"], ["o le agasala a Isaraelu;", "the sin of Israel, shall be destroyed:"], ["e tutupu ae le laau tuitui ma le laau talatala i o latou fata faitaulaga;", "the thorn and the thistle shall come up on their altars;"], ["latou te fai atu foi i mauga,", "and they shall say to the mountains,"], ["Ina tanu mai ia ia te i matou. E faapea foi i mea maupuepue,", "Cover us; and to the hills,"], ["Ina mafuli mai ia i luga ia te i matou.", "Fall on us."]]},
  {num:9,words:[["Isaraelu e,", "O Israel,"], ["talu mai ona po o Kipea ua e agasala ai;", "thou hast sinned from the days of Gibeah:"], ["ua latou tutumau ai;", "there they stood:"], ["na le oo atu ia te i latou i Kipea le taua i tagata agaleaga.", "the battle in Gibeah against the children of iniquity did not overtake them."]]},
  {num:10,words:[["O lo'u loto,", "It is in my desire that I should chastise them;"], ["ou te aoai ia te i latou; e faapotopotoina foi tagata e tau ma i latou,", "and the people shall be gathered against them,"], ["pe a ou fusifusi ia te i latou ona o a latou agasala e lua.", "when they shall bind themselves in their two furrows."]]},
  {num:11,words:[["O Efaraima foi o le povi fafine ia ua a'oa'oina,", "And Ephraim is as an heifer that is taught,"], ["ua fia soli saito lava;", "and loveth to tread out the corn;"], ["a ua ou alu atu lava a'u i lona ua lalelei;", "but I passed over upon her fair neck: I will make Ephraim to ride;"], ["ou te faatietie se tasi ia Efaraima,", "Judah shall plow,"], ["e suatia le eleele e Iuta e faamăluluina e Iakopo lona laueleele.", "and Jacob shall break his clods."]]},
  {num:12,words:[["Ia outou lulu saito mo outou ma le amiotonu,", "Sow to yourselves in righteousness,"], ["ia outou selesele mai ma le amio lelei;", "reap in mercy;"], ["ia outou suatia lo outou fanua vaoa; auā ua oo i ona po e saili atu ai ia Ieova,", "break up your fallow ground:"], ["seia afio mai o ia,", "for it is time to seek the LORD,"], ["ma faatotō ifo le amiotonu i luga ia te outou.", "till he come and rain righteousness upon you."]]},
  {num:13,words:[["Ua outou suatia le agasala,", "Ye have plowed wickedness,"], ["ua outou selesele mai le leaga;", "ye have reaped iniquity;"], ["ua outou aai le fua o le pepelo;", "ye have eaten the fruit of lies:"], ["auā na e faatuatua i lou ala,", "because thou didst trust in thy way,"], ["ma le toatele o ou tagata totoa.", "in the multitude of thy mighty men."]]},
  {num:14,words:[["O lea e tupu ai le vāvāō i ou tagata,", "Therefore shall a tumult arise among thy people,"], ["e faaumatia ou 'olo uma lava,", "and all thy fortresses shall be spoiled,"], ["e pei ona faaumatia e Salemana o Petarepelu i le aso na tau ai le taua;", "as Shalman spoiled Beth-arbel in the day of battle:"], ["na palasi le tinā faatasi ma ana tama.", "the mother was dashed in pieces upon her children."]]},
  {num:15,words:[["E faapea lava ona faia ia te outou i Peteli ona o la outou amio e matuā leaga;", "So shall Beth-el do unto you because of your great wickedness:"], ["e matuā fano lava le tupu o Isaraelu i le taeao.", "in a morning shall the king of Israel utterly be cut off."]]},
];
renderVerseSet(hos_ch_10_Verses, 'hos-ch10-verses');

var hos_ch_11_Verses = [
  {num:1,words:[["O ona po na tama itiiti ai Isaraelu,", "When Israel was a child,"], ["na ou alofa atu ia te ia,", "then I loved him,"], ["na ou valaauina foi lo'u atalii nai Aikupito.", "and called my son out of Egypt."]]},
  {num:2,words:[["Na latou alalaga ia te i latou,", "As they called them,"], ["a ua latou o ese ia te i latou;", "so they went from them:"], ["na latou fai taulaga ia Paala,", "they sacrificed unto Baalim,"], ["ma faamu mea manogi i tupua ua ta.", "and burned incense to graven images."]]},
  {num:3,words:[["Na ou a'oa'oina Efaraima ia savali,", "I taught Ephraim also to go,"], ["o loo o tauta'ita'i ia te i latou i o latou lima;", "taking them by their arms;"], ["a ua le iloa e i latou ona ou faamaloloina o i latou.", "but they knew not that I healed them."]]},
  {num:4,words:[["Na ou tosina i latou i maea a le tagata,", "I drew them with cords of a man,"], ["o maea alofa lava;", "with bands of love:"], ["na ou i ai ia te i latou e pei o e sii ae le amo ai o latou aulamu,", "and I was to them as they that take off the yoke on their jaws,"], ["na au tuuina atu foi mea e 'ai ia te i latou.", "and I laid meat unto them."]]},
  {num:5,words:[["E le toe foi o ia i le nuu o Aikupito,", "He shall not return into the land of Egypt,"], ["a e avea le Asuria mona tupu;", "but the Assyrian shall be his king,"], ["auā ua le mafafai i latou ona toe foi atu.", "because they refused to return."]]},
  {num:6,words:[["E tumau le pelu i ona aai,", "And the sword shall abide on his cities,"], ["e faaumatia ai foi ona la,", "and shall consume his branches,"], ["ma fano ai,", "and devour them,"], ["auā o a latou lava filifiliga.", "because of their own counsels."]]},
  {num:7,words:[["Ua naunau lo'u nuu e liliu ese ia te au;", "And my people are bent to backsliding from me:"], ["latou te valaau i ai e o mai i lē Silisili ese,", "though they called them to the most High,"], ["a e leai se tasi e vivii atu ia te ia .", "none at all would exalt him."]]},
  {num:8,words:[["Efaraima e,", "How shall I give thee up,"], ["ou te mafai faapefea ona tuu atu ia te oe? Isaraelu e,", "Ephraim? how shall I deliver thee,"], ["ou te tuuina atu oe faapefea? ou te mafai faapefea ona tuuina atu o oe e pei o Atama? ou te tuuina atu oe faapefea e pei o Sepoima? Ua liua lo'u loto i totonu ia te au;", "Israel? how shall I make thee as Admah? how shall I set thee as Zeboim? mine heart is turned within me,"], ["atoa foi ma lo'u alofa mutimutivale ua tupu.", "my repentings are kindled together."]]},
  {num:9,words:[["Ou te le faaoo lo'u ita tele;", "I will not execute the fierceness of mine anger,"], ["ou te le toe faaumatia Efaraima;", "I will not return to destroy Ephraim:"], ["auā o a'u o le Atua,", "for I am God,"], ["a e le se tagata,", "and not man;"], ["o le Paia o loo i totonu ia te oe;", "the Holy One in the midst of thee:"], ["ou te le alu atu ma le ita.", "and I will not enter into the city."]]},
  {num:10,words:[["Latou te mulimuli atu ia Ieova,", "They shall walk after the LORD:"], ["e tagi lava ia e pei o se leona;", "he shall roar like a lion:"], ["a tagi o ia,", "when he shall roar,"], ["ona taalise mai ai lea o le fanau mai sisifo.", "then the children shall tremble from the west."]]},
  {num:11,words:[["Latou te taalise mai e pei o se manu lele mai Aikupito,", "They shall tremble as a bird out of Egypt,"], ["e pei o se lupe foi mai le nuu o Asuria;", "and as a dove out of the land of Assyria:"], ["ou te faanonofo foi ia te i latou i o latou fale,", "and I will place them in their houses,"], ["ua faapea mai ai Ieova.", "saith the LORD."]]},
  {num:12,words:[["Ua siosio Efaraima ia te au i le pepelo,", "Ephraim compasseth me about with lies,"], ["o le aiga foi o Isaraelu ua siosio ia te au i le 'ole'ole;", "and the house of Israel with deceit:"], ["a ua pule pea Iuta faatasi ma le Atua,", "but Judah yet ruleth with God,"], ["ua faamaoni ia faatasi ma le au paia.", "and is faithful with the saints."]]},
];
renderVerseSet(hos_ch_11_Verses, 'hos-ch11-verses');

var hos_ch_12_Verses = [
  {num:1,words:[["O loo 'ai Efaraima le matagi,", "Ephraim feedeth on wind,"], ["ua naunau atu o ia i le matagi mai sasae;", "and followeth after the east wind:"], ["ua faateleina e ia le pepelo ma le malaia i aso uma lava;", "he daily increaseth lies and desolation;"], ["ua osia foi la latou feagaiga ma Asuria,", "and they do make a covenant with the Assyrians,"], ["ma ua avatu i Aikupito suāuu.", "and oil is carried into Egypt."]]},
  {num:2,words:[["Ua ia Ieova le finauga ma Iuta,", "The LORD hath also a controversy with Judah,"], ["na te faasalaina Iakopo e tusa ma ana amio;", "and will punish Jacob according to his ways;"], ["na te taui atu ia te ia e tusa ma ana galuega.", "according to his doings will he recompense him."]]},
  {num:3,words:[["Na ia tago i le mulivae o lona uso a o i ai i le manava;", "He took his brother by the heel in the womb,"], ["o lona malosi na ia malo ai i le Atua.", "and by his strength he had power with God:"]]},
  {num:4,words:[["Na ia malo i le agelu,", "Yea,"], ["na manumalo ai lava;", "he had power over the angel,"], ["na ia tagi,", "and prevailed: he wept,"], ["ma aioi atu ia te ia;", "and made supplication unto him:"], ["na ia iloa ia te ia i Peteli,", "he found him in Beth-el,"], ["na tŭlei mai ai foi lona siufofoga ia te i tatou.", "and there he spake with us;"]]},
  {num:5,words:[["O Ieova lava o le Atua o 'au;", "Even the LORD God of hosts;"], ["o Ieova o lona suafa lea e manatua ai o ia.", "the LORD is his memorial."]]},
  {num:6,words:[["O lenei,", "Therefore turn thou to thy God:"], ["ia e toe foi i lou Atua; ia e tausi le alofa ma le faamasinoga,", "keep mercy and judgment,"], ["aua le aunoa ona e faatalitali atu i lou Atua.", "and wait on thy God continually."]]},
  {num:7,words:[["O le faatauoa ia ,", "He is a merchant,"], ["o i lona lima o fua faatautau faaletatau;", "the balances of deceit are in his hand:"], ["e fiafia o ia i le faasaua.", "he loveth to oppress."]]},
  {num:8,words:[["Ua faapea mai foi a Efaraima, E moni,", "And Ephraim said,"], ["o a'u o le mau mea,", "Yet I am become rich,"], ["ua ou maua oloa mo a'u;", "I have found me out substance:"], ["latou te le iloa se leaga ia te au, se mea o se agasala i a'u galuega uma.", "in all my labours they shall find none iniquity in me that were sin."]]},
  {num:9,words:[["O a'u foi o Ieova lou Atua talu mai le nuu o Aikupito,", "And I that am the LORD thy God from the land of Egypt will yet make thee to dwell in tabernacles,"], ["ou te toe faanofo ia te oe i fale ie faapei o ona po o le tausamiga.", "as in the days of the solemn feast."]]},
  {num:10,words:[["Na ou tautala atu i perofeta,", "I have also spoken by the prophets,"], ["na ou faateleina faaaliga;", "and I have multiplied visions, and used similitudes,"], ["o le au perofeta foi na ou sauni atu ai upu faataoto.", "by the ministry of the prophets."]]},
  {num:11,words:[["Ua leaga lava Kiliata,", "Is there iniquity in Gilead? surely they are vanity:"], ["e pepelo lava i latou;", "they sacrifice bullocks in Gilgal;"], ["latou te fai taulaga i povi poa i Kilikala; o latou fata faitaulaga foi,", "yea,"], ["e pei o faupuegāmaa ia i atu pue o le laueleele.", "their altars are as heaps in the furrows of the fields."]]},
  {num:12,words:[["Na sola Iakopo i le nuu o Suria;", "And Jacob fled into the country of Syria,"], ["na auauna Isaraelu e maua ai lana avā;", "and Israel served for a wife,"], ["na ia leoleo mamoe e maua ai lana avā.", "and for a wife he kept sheep."]]},
  {num:13,words:[["O le perofeta na aveina ae ai Isaraelu e Ieova mai Aikupito;", "And by a prophet the LORD brought Israel out of Egypt,"], ["o le perofeta foi na leoleoina ai o ia.", "and by a prophet was he preserved."]]},
  {num:14,words:[["Na matuā faaonoono Efaraima ia te ia ,", "Ephraim provoked him to anger most bitterly:"], ["o le mea lea na te tuu ai pea lona toto ia te ia;", "therefore shall he leave his blood upon him,"], ["o lona luma foi e faafoisia ia te ia e lona Alii.", "and his reproach shall his Lord return unto him."]]},
];
renderVerseSet(hos_ch_12_Verses, 'hos-ch12-verses');

var hos_ch_13_Verses = [
  {num:1,words:[["Na tautala Efaraima ona tupu ai lea o le tetemu,", "When Ephraim spake trembling,"], ["sa mamalu o ia i Isaraelu;", "he exalted himself in Israel;"], ["a ua oo ina agasala o ia i Paala,", "but when he offended in Baal,"], ["ona oti ai lea.", "he died."]]},
  {num:2,words:[["A o nei ona po ua latou saga agasala pea,", "And now they sin more and more,"], ["ua latou faia mo i latou o tupua uamea,", "and have made them molten images of their silver,"], ["o tupua ua faia i o latou ario, e tusa ma lo latou manatu;", "and idols according to their own understanding,"], ["o le galuega a tufuga na mea uma;", "all of it the work of the craftsmen:"], ["ua faapea la latou upu i ai,", "they say of them,"], ["Ia feasogi ma tamai povi tagata o e fai taulaga.", "Let the men that sacrifice kiss the calves."]]},
  {num:3,words:[["O le mea lea e avea ai i latou e pei o le puao i le taeao,", "Therefore they shall be as the morning cloud,"], ["e pei o le sau foi i le vave ao ona mavae atu;", "and as the early dew that passeth away,"], ["e pei o le aputi ua lelea i le matagi i le mea e sasa ai saito,", "as the chaff that is driven with the whirlwind out of the floor,"], ["e pei o le asu foi ai le alaasu.", "and as the smoke out of the chimney."]]},
  {num:4,words:[["A o a'u o Ieova, o lou Atua talu mai le nuu o Aikupito,", "Yet I am the LORD thy God from the land of Egypt,"], ["e te le iloa se tasi Atua na o a'u;", "and thou shalt know no god but me:"], ["e leai foi se isi faaola, na o a'u.", "for there is no saviour beside me."]]},
  {num:5,words:[["Na ou iloa oe i le vao,", "I did know thee in the wilderness,"], ["o le nuu naumati.", "in the land of great drought."]]},
  {num:6,words:[["E pei ona fagaina o i latou,", "According to their pasture,"], ["sa faapea ona maoona o i latou;", "so were they filled;"], ["sa maoona i latou,", "they were filled,"], ["ona faamaualulugaina lea o latou loto;", "and their heart was exalted;"], ["o le mea lea na latou faagalogalo ai ia te au.", "therefore have they forgotten me."]]},
  {num:7,words:[["O lea ua avea ai a'u ia te i latou e pei o se leona;", "Therefore I will be unto them as a lion:"], ["ou te lamalama e pei o se nameri i le auala.", "as a leopard by the way will I observe them:"]]},
  {num:8,words:[["Ou te oso atu ia te i latou e pei o se urosa ua avea ana tama ,", "I will meet them as a bear that is bereaved of her whelps,"], ["ou te saeia mea e ufitai o latou fatu;", "and will rend the caul of their heart,"], ["ou te 'aina i latou i lea mea e pei o se leona;", "and there will I devour them like a lion:"], ["e saeia i latou e le manu feai.", "the wild beast shall tear them."]]},
  {num:9,words:[["Isaraelu e,", "O Israel,"], ["ua malaia oe ia te oe;", "thou hast destroyed thyself;"], ["a ua ia te au lou fesoasoani.", "but in me is thine help."]]},
  {num:10,words:[["O ifea o i ai nei lou tupu le na te faaolaina oe i o outou aai uma? o ifea ou faamasino foi na e fai mai ai,", "I will be thy king: where is any other that may save thee in all thy cities? and thy judges of whom thou saidst,"], ["Au mai ia te au se tupu atoa ma ni alii?", "Give me a king and princes?"]]},
  {num:11,words:[["Na ou avatu ia te oe le tupu i lo'u tiga;", "I gave thee a king in mine anger,"], ["na ou aveeseina foi o ia i lo'u ita.", "and took him away in my wrath."]]},
  {num:12,words:[["Ua fusifusi faatasi le leaga o Efaraima;", "The iniquity of Ephraim is bound up;"], ["ua teua lana agasala.", "his sin is hid."]]},
  {num:13,words:[["E oo ia te ia le faatiga o le fafine o le a fanau mai;", "The sorrows of a travailing woman shall come upon him:"], ["o ia o le tama faalemafaufau,", "he is an unwise son;"], ["aua e le tatau ona tuai mai o ia nai le mea e o ifo ai tama.", "for he should not stay long in the place of the breaking forth of children."]]},
  {num:14,words:[["Ou te laveai ia te i latou ai le malosi o le tuugamau;", "I will ransom them from the power of the grave; I will redeem them from death:"], ["ou te faaola ia te i latou ai le oti. Le oti e,", "O death, I will be thy plagues;"], ["o fea o i ai le malaia mai ia te oe? Le tuugamau e,", "O grave,"], ["o fea o i ai se mea e fano ai mai ia te oe? e lilo ia te au le salamo.", "I will be thy destruction: repentance shall be hid from mine eyes."]]},
  {num:15,words:[["E ui ina faauluolaina o ia i luma o ona uso,", "Though he be fruitful among his brethren,"], ["e agi mai le matagi mai sasae,", "an east wind shall come,"], ["o le matagi o Ieova e oso atu ia ai le vao,", "the wind of the LORD shall come up from the wilderness,"], ["e pe lona vaieli,", "and his spring shall become dry,"], ["e mate foi lona punavai;", "and his fountain shall be dried up:"], ["na te faaumatia le oa o mea uma e manaomia.", "he shall spoil the treasure of all pleasant vessels."]]},
  {num:16,words:[["E faasalaina Samaria,", "Samaria shall become desolate;"], ["auā ua ia fouvale i lona Atua;", "for she hath rebelled against her God:"], ["o le pelu latou te pauu ai;", "they shall fall by the sword:"], ["e palasi a latou tama meamea,", "their infants shall be dashed in pieces,"], ["e faatiauina o latou fafine ua totō.", "and their women with child shall be ripped up."]]},
];
renderVerseSet(hos_ch_13_Verses, 'hos-ch13-verses');

var hos_ch_14_Verses = [
  {num:1,words:[["Isaraelu e ina toe foi mai ia ia Ieova lou Atua;", "O Israel, return unto the LORD thy God;"], ["auā o lau agasala ua e paū ai.", "for thou hast fallen by thine iniquity."]]},
  {num:2,words:[["Ina sauni atu ia ni a outou upu ma toe foi atu ia Ieova. Ia outou faapea atu ia te ia,", "Take with you words, and turn to the LORD:"], ["Ia e ave ese agasala uma,", "say unto him,"], ["ma talileleia mai,", "Take away all iniquity,"], ["matou te avatua lava taulaga o matou laugutu.", "and receive us graciously: so will we render the calves of our lips."]]},
  {num:3,words:[["E le faaolaina i matou e Asuria;", "Asshur shall not save us;"], ["matou te le tietie i solofanua;", "we will not ride upon horses:"], ["matou te le toe faapea ane lava i galuega a o matou lima,", "neither will we say any more to the work of our hands,"], ["O matou atua ia;", "Ye are our gods:"], ["auā e alofagia e oe le mātuaoti.", "for in thee the fatherless findeth mercy."]]},
  {num:4,words:[["Ou te faamaloloina lo latou liliu ese;", "I will heal their backsliding,"], ["ou te alofa fua ia te i latou;", "I will love them freely:"], ["auā ua liliueseina lo'u ita ia te i latou.", "for mine anger is turned away from him."]]},
  {num:5,words:[["E avea a'u ma sau ia Isaraelu;", "I will be as the dew unto Israel:"], ["e fuga mai o ia e pei o le susana,", "he shall grow as the lily,"], ["e sosolo ona aa e pei o Lepanona.", "and cast forth his roots as Lebanon."]]},
  {num:6,words:[["E tutupu ae ona tātupu,", "His branches shall spread,"], ["e pei o le olive lona matagofie;", "and his beauty shall be as the olive tree,"], ["e manogi foi ia e pei o Lepanona.", "and his smell as Lebanon."]]},
  {num:7,words:[["O i latou o e nonofo i lalo ifo o lona paolo,", "They that dwell under his shadow shall return;"], ["e toe ola mai i latou e pei o saito,", "they shall revive as the corn,"], ["e fua mai e pei o le vine;", "and grow as the vine:"], ["e ta'ua o ia e pei o le uaina o Lepanona. E faapea mai a Efaraima,", "the scent thereof shall be as the wine of Lebanon."]]},
  {num:8,words:[["Se a ea sa'u toe mea e fai i tupua? Ua ou tali atu,", "Ephraim shall say,"], ["ma vaavaai atu ia te ia;", "What have I to do any more with idols? I have heard him,"], ["e pei o se perosi lauolaola a'u nei;", "and observed him:"], ["e maua lau fua mai ia te au.", "I am like a green fir tree. From me is thy fruit found."]]},
  {num:9,words:[["Po o ai se tasi ua poto? e iloa lava e ia na mea;", "Who is wise,"], ["po o ai lē faautauta? e iloa ai e ia;", "and he shall understand these things? prudent,"], ["auā ua tonu ala o Ieova, e savavali ai e ua amiotonu;", "and he shall know them? for the ways of the LORD are right,"], ["a o e fouvale,", "and the just shall walk in them:"], ["e tautevateva ai i latou.", "but the transgressors shall fall therein."]]},
];
renderVerseSet(hos_ch_14_Verses, 'hos-ch14-verses');

})();